import{_ as a,c as t,o as n,a1 as i}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse(`{"title":"Features: Plan & Code Review | Plannotator","description":"Learn Plannotator's core features for reviewing AI plans and code changes. Master visual plan review, annotations, image attachments, and code diff review.","frontmatter":{"title":"Features: Plan & Code Review | Plannotator","sidebarTitle":"Platform Features","subtitle":"Platform Features","description":"Learn Plannotator's core features for reviewing AI plans and code changes. Master visual plan review, annotations, image attachments, and code diff review.","order":2},"headers":[],"relativePath":"backnotprop/plannotator/platforms/index.md","filePath":"backnotprop/plannotator/platforms/index.md"}`),r={name:"backnotprop/plannotator/platforms/index.md"};function o(s,e,l,d,c,h){return n(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="platform-features" tabindex="-1">Platform Features <a class="header-anchor" href="#platform-features" aria-label="Permalink to &quot;Platform Features&quot;">​</a></h1><p>This chapter introduces Plannotator&#39;s two core features: <strong>Plan Review</strong> and <strong>Code Review</strong>. You&#39;ll learn how to visually review AI-generated plans, add various types of comments, attach image annotations, and review git diff code changes.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Before You Begin</p><p>Before studying this chapter, ensure you have completed the following preparations:</p><ul><li>✅ Completed <a href="./../start/getting-started/">Quick Start</a> tutorial</li><li>✅ Installed Plannotator plugin (<a href="./../start/installation-claude-code/">Claude Code</a> or <a href="./../start/installation-opencode/">OpenCode</a>)</li></ul></div><h2 id="chapter-contents" tabindex="-1">Chapter Contents <a class="header-anchor" href="#chapter-contents" aria-label="Permalink to &quot;Chapter Contents&quot;">​</a></h2><h3 id="plan-review" tabindex="-1">Plan Review <a class="header-anchor" href="#plan-review" aria-label="Permalink to &quot;Plan Review&quot;">​</a></h3><p>Learn how to review AI-generated execution plans, add modification suggestions, and let AI execute according to your intent.</p><table tabindex="0"><thead><tr><th>Tutorial</th><th>Description</th></tr></thead><tbody><tr><td>---</td><td>---</td></tr><tr><td><a href="./plan-review-annotations/">Add Plan Annotations</a></td><td>Master adding different types of annotations in plans (delete, replace, insert, comment)</td></tr><tr><td><a href="./plan-review-images/">Add Image Annotations</a></td><td>Learn to attach images in plan review and use pen, arrow, circle tools for annotation</td></tr></tbody></table><h3 id="code-review" tabindex="-1">Code Review <a class="header-anchor" href="#code-review" aria-label="Permalink to &quot;Code Review&quot;">​</a></h3><p>Learn how to review code changes, add line-level comments, and discover issues before committing.</p><table tabindex="0"><thead><tr><th>Tutorial</th><th>Description</th></tr></thead><tbody><tr><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td></tr><tr><td><a href="./code-review-diff-types/">Switch Diff Views</a></td><td>Learn to switch between different diff types in code review (uncommitted/staged/last commit/branch)</td></tr></tbody></table><h2 id="learning-path" tabindex="-1">Learning Path <a class="header-anchor" href="#learning-path" aria-label="Permalink to &quot;Learning Path&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Recommended Learning Sequence</p><p>Choose the appropriate learning path based on your use case:</p><p><strong>Path A: Plan Review First</strong> (Recommended for beginners)</p><ol><li><a href="./plan-review-basics/">Plan Review Basics</a> → First learn the basic plan review process</li><li><a href="./plan-review-annotations/">Add Plan Annotations</a> → Learn how to precisely modify plans</li><li><a href="./plan-review-images/">Add Image Annotations</a> → Use images to express intent more clearly</li><li>Then learn the code review series</li></ol><p><strong>Path B: Code Review First</strong> (Suitable for developers with Code Review experience)</p><ol><li><a href="./code-review-basics/">Code Review Basics</a> → Familiarize with code review interface</li><li><a href="./code-review-annotations/">Add Code Comments</a> → Learn line-level comments</li><li><a href="./code-review-diff-types/">Switch Diff Views</a> → Master different diff types</li><li>Then learn the plan review series</li></ol></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>After completing this chapter, you can continue learning:</p><ul><li><a href="./../advanced/url-sharing/">URL Sharing</a> - Share plans and comments via URL for team collaboration</li><li><a href="./../advanced/obsidian-integration/">Obsidian Integration</a> - Automatically save approved plans to Obsidian</li><li><a href="./../advanced/remote-mode/">Remote Mode</a> - Use Plannotator in SSH, devcontainer, WSL environments</li></ul>',16)])])}const m=a(r,[["render",o]]);export{f as __pageData,m as default};
